// Route inbound WhatsApp messages (Evolution MESSAGES_UPSERT webhook): owner-only,
// no-loop (skip our OWN sends), command-or-chat. Commands write to the vault inbox /
// action log; free text is marked needs_llm so the Groq node answers it with
// conversation memory and the morning nudge's focus. WhatsApp markup (*bold*,
// _italic_) is NATIVE, so replies are plain text - no HTML escaping needed.
const fs = require('fs');
const path = require('path');
const INBOX = '/data/inbox';
const ACTIONS = path.join(INBOX, '.actions.jsonl');
const OWNER = (typeof $env !== 'undefined' && $env.WA_TARGET_NUMBER)
  ? String($env.WA_TARGET_NUMBER).replace(/\D/g, '') : null;

const CHAT_SYSTEM = [
  "You are the user's Agentic Second Brain assistant, replying inside WhatsApp.",
  'Be warm, concise and genuinely useful - usually a few short lines, not an essay.',
  'You can also run commands; if the user wants to capture a thought or update a',
  'project, point them to: /note <text>, /touch <project>, /done <project>,',
  '/reopen <project>, /help. Never invent personal facts you were not given.',
  'Use only WhatsApp markup: *bold* (single asterisks) and _italics_.'
].join(' ');

// Focus the morning nudge left behind, so a follow-up like "explain more" is
// answered about the actual nudged project rather than as generic chat. Absent
// file -> behaves as a plain assistant. SEPARATE file from Telegram's so the two
// channels never cross-contaminate.
let focus = null;
try {
  const CTX = path.join(INBOX, '.wa_context.json');
  if (fs.existsSync(CTX)) focus = JSON.parse(String(fs.readFileSync(CTX, 'utf8')));
} catch (e) { focus = null; }
const hasFocus = !!(focus && ((focus.projects && focus.projects.length) || (focus.reviews && focus.reviews.length)));

// Short-term conversation memory (bounded, self-resetting) - its own WhatsApp file.
const HIST = path.join(INBOX, '.wa_history.json');
const MAX_TURNS = 8;
const HIST_TTL_MS = 6 * 3600 * 1000;
const clip = (s, n) => { s = String(s); return s.length > n ? s.slice(0, n) : s; };

let turns = [];
try {
  if (fs.existsSync(HIST)) {
    const h = JSON.parse(String(fs.readFileSync(HIST, 'utf8')));
    turns = Array.isArray(h.turns) ? h.turns : [];
    const updated = Date.parse(h.updated || '') || 0;
    const focusTs = (focus && Date.parse(focus.ts || '')) || 0;
    if ((focusTs && focusTs > updated) || (Date.now() - updated) > HIST_TTL_MS) turns = [];
  }
} catch (e) { turns = []; }

const saveHistory = (arr) => {
  try {
    fs.mkdirSync(INBOX, { recursive: true });
    fs.writeFileSync(HIST, JSON.stringify({ updated: new Date().toISOString(), turns: arr.slice(-MAX_TURNS) }));
  } catch (e) { /* best-effort memory */ }
};

const out = [];
for (const item of $input.all()) {
  const body = (item.json && item.json.body) || item.json || {};   // n8n webhook nests under .body
  const data = body.data || {};
  if (data.key && data.key.fromMe) continue;                       // no-loop: skip our own sends
  const msg = data.message || {};
  const text = String(msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || '').trim();
  const jid = (data.key && data.key.remoteJid) || '';
  if (jid.endsWith('@g.us') || jid === 'status@broadcast') continue;  // ignore groups/status
  const number = jid.replace(/@.*$/, '').replace(/\D/g, '');
  if (!number) continue;
  if (OWNER && number !== OWNER) continue;                          // owner-only (no stranger LLM bills)
  if (!text) continue;                                             // ignore media/empty

  if (!text.startsWith('/')) {
    let system = CHAT_SYSTEM
      + ' This is an ongoing conversation; use the prior messages for context and do not repeat yourself.';
    if (hasFocus) {
      system += ' CURRENT FOCUS - the user is following up on today\'s nudge. Focus data as JSON: '
        + JSON.stringify({ today: focus.today, projects: focus.projects, reviews: focus.reviews })
        + ' If they ask to explain more / why / how / where they left off, expand using this data and its recent_notes. If the message is clearly unrelated, answer normally without forcing the project in.';
    }
    // Build the full prompt: system, then bounded history, then the new message.
    const messages = [{ role: 'system', content: system }]
      .concat(turns.map((t) => ({ role: t.role === 'assistant' ? 'assistant' : 'user', content: String(t.content) })))
      .concat([{ role: 'user', content: text }]);
    // Persist the user turn now; Extract Reply appends the assistant turn after Groq.
    turns.push({ role: 'user', content: clip(text, 2000) });
    saveHistory(turns);
    out.push({ json: { needs_llm: true, messages } });
    continue;
  }

  // ---- Command handling (mirrors inbound-capture / the Telegram assistant) ----
  const m = text.match(/^\/(\w+)\s*([\s\S]*)$/);
  const cmd = (m ? m[1] : '').toLowerCase();
  const arg = m ? m[2].trim() : '';
  try { fs.mkdirSync(INBOX, { recursive: true }); } catch (e) {}

  let reply;
  if ((cmd === 'note' || cmd === 'n' || cmd === 'capture') && arg) {
    const ts = new Date();
    const slug = (arg.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40)) || 'note';
    const fname = ts.toISOString().slice(0, 10) + '-' + ts.getTime() + '-' + slug + '.md';
    const md = '---\ntype: capture\ncreated: ' + ts.toISOString() + '\nsource: whatsapp\n---\n\n' + arg + '\n';
    fs.writeFileSync(path.join(INBOX, fname), md);
    reply = '📥 Captured to inbox as _' + fname + '_';
  } else if ((cmd === 'done' || cmd === 'touch' || cmd === 'did' || cmd === 'reopen') && arg) {
    const action = cmd === 'done' ? 'done' : (cmd === 'reopen' ? 'reopen' : 'touch');
    fs.appendFileSync(ACTIONS, JSON.stringify({ ts: new Date().toISOString(), action, project: arg }) + '\n');
    reply = action === 'done'
      ? '✅ Marked _' + arg + '_ as done - it will not nudge you again.'
      : (action === 'reopen'
        ? '♻️ Reopened _' + arg + '_ - it can nudge you again.'
        : '👍 Logged activity on _' + arg + '_ - staleness clock reset.');
  } else if (cmd === 'help' || cmd === 'start') {
    reply = '*Second Brain*\nAsk me anything, or use:\n📥 /note <text> - capture a thought\n👍 /touch <project> - reset its staleness clock\n✅ /done <project> - stop nudging it\n♻️ /reopen <project> - undo a done\n❓ /help - show this';
  } else {
    reply = '🤖 Unknown or empty command. Send /help, or just ask me a question.';
  }
  out.push({ json: { needs_llm: false, reply } });
}

return out;

// Normalize the Groq reply for a WhatsApp chat answer. Unlike the morning nudge,
// an empty/blocked reply does NOT throw - a chat turn should always answer - so we
// fall back to a soft message that still surfaces the provider reason for debugging.
// WhatsApp markup (*bold*, _italic_) is NATIVE, so the text is kept as-is: no HTML
// rendering, no escaping.
const res = $input.first().json || {};
let text = '';
if (res.choices && res.choices[0] && res.choices[0].message) {
  text = res.choices[0].message.content || '';
} else if (res.candidates && res.candidates[0] && res.candidates[0].content) {
  text = (res.candidates[0].content.parts || []).map((p) => (p && p.text) || '').join('');
} else if (typeof res.content === 'string') {
  text = res.content;
}

text = String(text).trim();
const fence = text.match(/^```[a-zA-Z]*\r?\n?([\s\S]*?)\r?\n?```$/);
if (fence) text = fence[1].trim();

if (!text) {
  const reason = (res.error && res.error.message)
    || (res.choices && res.choices[0] && res.choices[0].finish_reason)
    || 'no content';
  text = '🤔 I could not generate a reply (' + reason + '). Try rephrasing, or send /help.';
}

if (text.length > 4000) text = text.slice(0, 3990) + '\n…';

// Append this answer to short-term memory so the next turn has context. The user
// turn was already saved by Route; we add the assistant turn here, same bounded
// window. Best-effort: memory must never break a reply.
try {
  const fsh = require('fs');
  const HIST = '/data/inbox/.wa_history.json';
  let turns = [];
  if (fsh.existsSync(HIST)) {
    const h = JSON.parse(String(fsh.readFileSync(HIST, 'utf8')));
    if (Array.isArray(h.turns)) turns = h.turns;
  }
  turns.push({ role: 'assistant', content: text.length > 2000 ? text.slice(0, 2000) : text });
  fsh.writeFileSync(HIST, JSON.stringify({ updated: new Date().toISOString(), turns: turns.slice(-8) }));
} catch (e) { /* best-effort memory */ }

return [{ json: { reply: text } }];
